function getContinent(country) {
  for (const continent of Object.keys(continentMap)) {
    if (continentMap[continent].includes(country)) return continent;
  }
  return 'Autre';
}

function renderVoyages() {
  const container = document.querySelector('#voyages') || (() => {
    const s = document.createElement('section'); s.id = 'voyages'; s.className = 'voyages'; document.body.appendChild(s); return s;
  })();

  const grouped = recipes.reduce((acc, r) => {
    const country = r.country || countryMap[r.title] || 'Autre';
    const continent = getContinent(country);
    acc[continent] = acc[continent] || {};
    acc[continent][country] = acc[continent][country] || [];
    acc[continent][country].push(r);
    return acc;
  }, {});

  const continentOrder = ['Europe', 'Amérique', 'Asie', 'Afrique', 'Océanie', 'Autre'];

  container.innerHTML = '';
  Object.keys(grouped)
    .sort((a, b) => (
      continentOrder.indexOf(a) - continentOrder.indexOf(b)
    ))
    .forEach(continent => {
      const continentSection = document.createElement('div');
      continentSection.className = 'continent-group';

      const continentTitle = document.createElement('h2');
      continentTitle.textContent = continent;
      continentSection.appendChild(continentTitle);

      Object.keys(grouped[continent]).sort().forEach(country => {
        const g = document.createElement('div');
        g.className = 'country-group';
        const h = document.createElement('h3'); h.textContent = country; g.appendChild(h);
        const ul = document.createElement('div'); ul.className = 'country-cards';

        grouped[continent][country].forEach(r => {
          const card = document.createElement('article'); card.className = 'card';
          card.innerHTML = `
            <img src="${r.img}" alt="${r.title}" loading="lazy">
            <h4>${r.title}</h4>
            <p>${r.excerpt}</p>
            <div class="meta">
              <button class="btn" data-id="${r.id}">Voir la recette</button>
            </div>
          `;
          card.addEventListener('click', (e) => { if (e.target.tagName !== 'BUTTON') { if (typeof openRecipe === 'function') openRecipe(r.id); } });
          ul.appendChild(card);
        });

        g.appendChild(ul);
        continentSection.appendChild(g);
      });

      container.appendChild(continentSection);
  });

  container.scrollIntoView({ behavior: 'smooth' });
}

function setupVoyagesNav() {
  // trouve le lien Voyages dans la nav (texte ou href)
  const navLinks = Array.from(document.querySelectorAll('nav a'));
  const link = navLinks.find(a => (a.textContent || '').trim().toLowerCase().includes('voyages') || (a.getAttribute('href')||'').includes('#voyages'));
  if (link) {
    link.addEventListener('click', (e) => { 
      e.preventDefault(); 
      let voyagesSection = document.querySelector('#voyages');
      if (!voyagesSection) {
        voyagesSection = document.createElement('section');
        voyagesSection.id = 'voyages';
        voyagesSection.className = 'voyages';
        voyagesSection.style.display = 'none';
        const contact = document.querySelector('#contact');
        if (contact && contact.parentNode) {
          contact.parentNode.insertBefore(voyagesSection, contact);
        } else {
          document.body.appendChild(voyagesSection);
        }
      }
      // Toggle affichage
      voyagesSection.style.display = voyagesSection.style.display === 'none' ? 'block' : 'none';
      if (voyagesSection.style.display === 'block') {
        renderVoyages();
      }
    });
  }
}

function setupRecipesNav() {
  // trouve le lien Recettes dans la nav
  const navLinks = Array.from(document.querySelectorAll('nav a'));
  const link = navLinks.find(a => (a.textContent || '').trim().toLowerCase().includes('recettes'));
  if (link) {
    link.addEventListener('click', (e) => { 
      e.preventDefault(); 
      const recipesSection = document.querySelector('#recipes');
      if (recipesSection) {
        // Toggle affichage
        recipesSection.style.display = recipesSection.style.display === 'none' ? 'block' : 'none';
      }
    });
  }
}

function setupContactsNav() {
  // trouve le lien Contact dans la nav
  const navLinks = Array.from(document.querySelectorAll('nav a'));
  const link = navLinks.find(a => (a.textContent || '').trim().toLowerCase().includes('contact'));
  if (link) {
    link.addEventListener('click', (e) => { 
      e.preventDefault(); 
      const contactSection = document.querySelector('#contact');
      if (contactSection) {
        // Toggle affichage
        contactSection.style.display = contactSection.style.display === 'none' ? 'block' : 'none';
      }
    });
  }
}

function moveContactsAfterVoyages() {
  let voyages = document.querySelector('#voyages');
  if (!voyages) {
    voyages = document.createElement('section');
    voyages.id = 'voyages'; voyages.className = 'voyages';
    const contactsCandidate = document.querySelector('#contacts, .contacts, #contact, .contact');
    if (contactsCandidate && contactsCandidate.parentNode) contactsCandidate.parentNode.insertBefore(voyages, contactsCandidate);
    else document.body.appendChild(voyages);
  }
  let contacts = document.querySelector('#contacts, .contacts, #contact, .contact');
  if (!contacts) {
    contacts = Array.from(document.querySelectorAll('section,div')).find(el => {
      const txt = (el.textContent || '').trim().toLowerCase();
      return txt.startsWith('contacts') || txt.startsWith('contact');
    }) || null;
  }
  if (contacts && voyages.parentNode) voyages.parentNode.insertBefore(contacts, voyages.nextSibling);
}

// Corriger l'image du houmous (si présent) de façon sûre
(function fixHoumousImage() {
  const h = recipes.find(r => (r.title || '').toLowerCase().includes('houmous') || (r.title || '').toLowerCase().includes('hummus'));
  if (h) {
    h.img = h.img && h.img.startsWith('data:') ? 'https://images.unsplash.com/photo-1544025162-d76694265947?auto=format&fit=crop&w=400&q=85' : h.img;
  }
})();

// initialisation au chargement
function initVoyagesRecipesAndContacts(){ 
  setupVoyagesNav();
  setupRecipesNav();
  setupContactsNav();
  // Afficher recettes au départ, cacher voyages et contacts
  const recipesSection = document.querySelector('#recipes');
  if (recipesSection) recipesSection.style.display = 'block';
  const voyagesSection = document.querySelector('#voyages');
  if (voyagesSection) voyagesSection.style.display = 'none';
  const contactSection = document.querySelector('#contact');
  if (contactSection) contactSection.style.display = 'none';
  if(typeof moveContactsAfterVoyages === 'function') moveContactsAfterVoyages(); 
}
if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', initVoyagesRecipesAndContacts); else initVoyagesRecipesAndContacts();

// Injecter un style via JS pour rétrécir les images des cartes (ne modifie pas l'HTML)
(function shrinkImages() {
  const css = `
    /* Voyages : groupe par pays, 4 cartes max par ligne */
    .country-group { margin-bottom: 20px; }
    .country-group h3 { margin: 0 0 8px 0; font-size: 1.1rem; }
    .country-cards { display:flex; flex-wrap:wrap; gap:1rem; align-items:flex-start; justify-content:center; }
    .country-cards .card { box-sizing:border-box; flex: 0 0 calc(25% - 0.75rem); max-width: calc(25% - 0.75rem); }
    .country-cards .card img { object-position:center center; }

    /* Règles générales pour les images des cartes (grille principale) */
    .cards .recipe-card img { width:160px; height:120px; object-fit:cover; border-radius:6px; display:block; }
    .recipe-card.mini img { width:140px; height:100px; }

    /* Ne pas écraser l'image dans le modal (garder taille actuelle) */
    .modal img, #modal img { width: 100% !important; height: 220px !important; object-fit: cover !important; }

    @media (max-width: 800px) {
      .country-cards .card { flex: 0 0 calc(50% - 0.75rem); max-width: calc(50% - 0.75rem); }
    }
    @media (max-width: 480px) {
      .country-cards .card { flex: 0 0 100%; max-width: 100%; }
    }
  `;
  const s = document.createElement('style');
  s.setAttribute('data-injected', 'shrink-images');
  s.appendChild(document.createTextNode(css));
  (document.head || document.documentElement).appendChild(s);
})();

function openRecipe(id){
  const r = recipes.find(x=>x.id===Number(id));
  if(!r) return;
  const ingHtml = r.ingredients.map(ing => `<li>${ing}</li>`).join('');
  const stepsHtml = r.steps.map(step => `<li>${step}</li>`).join('');
  modalBody.innerHTML = `
    <h2>${r.title}</h2>
    <p><strong>Catégorie:</strong> ${r.category} — <strong>Temps:</strong> ${r.time}</p>
    <img src="${r.img}" alt="${r.title}" style="width:100%;height:220px;object-fit:cover;border-radius:8px;margin:8px 0">
    <h4>Ingrédients</h4>
    <ul>${ingHtml}</ul>
    <h4>Préparation</h4>
    <ol>${stepsHtml}</ol>
  `;
  modal.setAttribute('aria-hidden','false');
}

function close() {
  modal.setAttribute('aria-hidden','true');
}

grid.addEventListener('click', (e)=>{
  const btn = e.target.closest('button[data-id]');
  if(btn){ openRecipe(btn.dataset.id) }
});

closeModal.addEventListener('click', close);
modal.addEventListener('click', (e)=>{ if(e.target===modal) close() });

function applyFilters(){
  const q = (search.value||'').toLowerCase().trim();
  const cat = filter.value;
  
  // Récupérer tous les pays uniques
  const countries = [...new Set(Object.values(countryMap))];
  
  // Vérifier si la recherche correspond à un pays
  const matchedCountry = countries.find(c => c.toLowerCase() === q) || 
                         (q !== '' && countries.find(c => c.toLowerCase().includes(q)));
  
  if (q !== '' && matchedCountry) {
    // Si c'est un pays, afficher les recettes de ce pays dans voyages
    const recipesFromCountry = recipes.filter(r => {
      const country = r.country || countryMap[r.title] || 'Autre';
      return country.toLowerCase() === matchedCountry.toLowerCase();
    });
    
    // Rendu personnalisé pour un seul pays
    const container = document.querySelector('#voyages') || (() => {
      const s = document.createElement('section'); s.id = 'voyages'; s.className = 'voyages'; document.body.appendChild(s); return s;
    })();
    
    container.innerHTML = '';
    const g = document.createElement('div'); g.className = 'country-group';
    const h = document.createElement('h3'); h.textContent = matchedCountry; g.appendChild(h);
    const ul = document.createElement('div'); ul.className = 'country-cards';
    recipesFromCountry.forEach(r => {
      const card = document.createElement('article'); card.className = 'card';
      card.innerHTML = `
        <img src="${r.img}" alt="${r.title}" loading="lazy">
        <h4>${r.title}</h4>
        <p>${r.excerpt}</p>
        <div class="meta">
          <button class="btn" data-id="${r.id}">Voir la recette</button>
        </div>
      `;
      card.addEventListener('click', (e) => { if (e.target.tagName !== 'BUTTON') { if (typeof openRecipe === 'function') openRecipe(r.id); } });
      ul.appendChild(card);
    });
    g.appendChild(ul);
    container.appendChild(g);
    
    // Afficher voyages, masquer recettes
    document.querySelector('#voyages').style.display = 'block';
    document.querySelector('#recipes').style.display = 'none';
  } else {
    // Sinon, filtre normal pour recettes
    const filtered = recipes.filter(r=>{
      const byCat = cat==='all' ? true : r.category===cat;
      const byQ = q === '' ? true : (r.title + ' ' + r.excerpt).toLowerCase().includes(q);
      return byCat && byQ;
    });
    renderCards(filtered);
    
    // Masquer voyages, afficher recettes
    const voyagesSection = document.querySelector('#voyages');
    if (voyagesSection) voyagesSection.style.display = 'none';
    document.querySelector('#recipes').style.display = 'block';
  }
}

search.addEventListener('input', applyFilters);
filter.addEventListener('change', applyFilters);

renderCards(recipes);
